  1→import { createWall } from '@/domain/models';
  2→import { distance } from '@/geometry/point';
  3→import { nearestPointOnSegment } from '@/geometry/line';
  4→import { SNAP_DISTANCE_PX, MIN_WALL_LENGTH } from '@/domain/defaults';
  5→
  6→function snapToWalls(modelPos, walls, snapDistModel, chainStart) {
  7→  let best = null;
  8→  let bestDist = snapDistModel;
  9→
 10→  // Snap to chain start to close loop (highest priority)
 11→  if (chainStart) {
 12→    const d = distance(modelPos, chainStart);
 13→    if (d < bestDist) {
 14→      best = chainStart;
 15→      bestDist = d;
 16→    }
 17→  }
 18→
 19→  // Snap to wall endpoints
 20→  for (const wall of walls) {
 21→    for (const pt of [wall.start, wall.end]) {
 22→      const d = distance(modelPos, pt);
 23→      if (d < bestDist) {
 24→        best = pt;
 25→        bestDist = d;
 26→      }
 27→    }
 28→  }
 29→
 30→  // If no endpoint found, try snapping to nearest point on wall segments
 31→  if (!best) {
 32→    for (const wall of walls) {
 33→      const { point, t } = nearestPointOnSegment(modelPos, wall.start, wall.end);
 34→      if (t <= 0.001 || t >= 0.999) continue; // too close to endpoints, already covered
 35→      const d = distance(modelPos, point);
 36→      if (d < bestDist) {
 37→        best = point;
 38→        bestDist = d;
 39→      }
 40→    }
 41→  }
 42→
 43→  return best;
 44→}
 45→
 46→function constrainAngle(start, end, shiftHeld) {
 47→  if (!shiftHeld) return end;
 48→  const dx = end.x - start.x;
 49→  const dy = end.y - start.y;
 50→  const angle = Math.atan2(dy, dx);
 51→  const snapAngle = Math.round(angle / (Math.PI / 4)) * (Math.PI / 4);
 52→  const len = Math.sqrt(dx * dx + dy * dy);
 53→  return {
 54→    x: start.x + Math.cos(snapAngle) * len,
 55→    y: start.y + Math.sin(snapAngle) * len,
 56→  };
 57→}
