 46→      if ((e.ctrlKey || e.metaKey) && e.key === 's') {
 47→        e.preventDefault();
 48→        handleSave();
 49→      }
 50→    };
 51→    window.addEventListener('keydown', handler);
 52→    return () => window.removeEventListener('keydown', handler);
 53→  }, [handleSave]);
 54→
 55→  const handleLoadClick = useCallback(async () => {
 56→    setSavedProjects(await listProjects());
 57→    setShowLoadModal(true);
 58→  }, []);
 59→
 60→  const handleLoad = useCallback(async (id) => {
 61→    if (isDirty && !window.confirm('Unsaved changes will be lost. Continue?')) return;
 62→    try {
 63→      const { project: loaded, savedAt } = await loadProject(id);
 64→      dispatch({ type: 'PROJECT_LOAD', project: loaded, savedAt });
 65→      setShowLoadModal(false);
 66→    } catch (err) {
 67→      alert('Failed to load project: ' + err.message);
 68→    }
 69→  }, [isDirty, dispatch]);
 70→
 71→  const activeFloorId = project.floors[0]?.id;
 72→
 73→  return (
 74→    <EditorProvider activeFloorId={activeFloorId}>
 75→      <div className={styles.layout}>
