 77→          <Toolbar onNew={handleNew} onSave={handleSave} onLoad={handleLoadClick} />
 78→        </div>
 79→        <div className={styles.sidebar}>
 80→          <Sidebar />
 81→        </div>
 82→        <div className={styles.canvas}>
 83→          <SvgCanvas />
 84→        </div>
 85→        <div className={styles.properties}>
 86→          <PropertiesPanel />
 87→        </div>
 88→      </div>
 89→
 90→      {showLoadModal && (
 91→        <Modal title="Load Project" onClose={() => setShowLoadModal(false)}>
 92→          {savedProjects.length === 0 ? (
 93→            <p style={{ color: 'var(--color-text-secondary)', fontSize: '13px' }}>
 94→              No saved projects found.
 95→            </p>
 96→          ) : (
 97→            <div style={{ display: 'flex', flexDirection: 'column', gap: '8px' }}>
 98→              {savedProjects.map(p => (
 99→                <button
100→                  key={p.id}
101→                  onClick={() => handleLoad(p.id)}
102→                  style={{
103→                    display: 'flex',
104→                    justifyContent: 'space-between',
105→                    padding: '10px 12px',
106→                    border: '1px solid var(--color-border)',
107→                    borderRadius: 'var(--radius-sm)',
108→                    cursor: 'pointer',
109→                    background: 'white',
110→                    fontSize: '13px',
